public class DelayedActionQueue implements ActionQueue {
    private static final Logger LOGGER = LoggerFactory.getLogger(DelayedActionQueue.class);
    private final ConcurrentLinkedQueue<Runnable> queue = new ConcurrentLinkedQueue<>();

    @Override
    public void add(Runnable action) {
        queue.add(action);
    }

    @Override
    public void tryCompleteActions() {
        int maxToComplete = queue.size();
        for (int count = 0; count < maxToComplete; count++) {
            try {
                Runnable action = queue.poll();
                if (action == null) return;
                action.run();
            } catch (Exception e) {
                LOGGER.error("failed to complete delayed actions", e);
            }
        }
    }
}

public class ConsumerAttr {
    String group;
    LanguageCode language;
    int version;
    ConsumeType consumeMode;

    public ConsumerAttr(String group, LanguageCode language, int version, ConsumeType consumeMode) {
        this.group = group;
        this.language = language;
        this.version = version;
        this.consumeMode = consumeMode;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o)
            return true;
        if (o == null || getClass() != o.getClass())
            return false;
        ConsumerAttr attr = (ConsumerAttr) o;
        return version == attr.version && Objects.equal(group, attr.group) && language == attr.language && consumeMode == attr.consumeMode;
    }

    @Override
    public int hashCode() {
        return Objects.hashCode(group, language, version, consumeMode);
    }
}

